/// <summary>
/// Extension of the <c>InventDimParmFixed</c> form for the ETGSPAIN model.
/// </summary>
[ExtensionOf(formstr(InventDimParmFixed))]
final class InventDimParmFixedETGSPAIN_Extension
{    
}

Method.Source:
/// <summary>
/// Extension of the <c>setDesign</c> method.
/// </summary>
void setDesign()
{
    next setDesign();

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
    FormRun   formRun = this.args().caller();


        // Solamente hacemos los cambios si se llama desde los siguientes formularios.
        if (formRun.args().name() == formStr(PurchAgreementGenerateReleaseOrder) ||
        formRun.args().name() == formStr(SalesAgreementGenerateReleaseOrder))
        {

            InventDimParm enabled;
            InventDimParm show;
            InventDimParm productDim;

            enabled.data(inventDimSetupObject.parmDimParmLockedRightClick());

            if (smallGrp.visible())
            {
                enabled.toggleAllInventDim();
            }
            else
            {
                enabled.toggleAllInventDimLargeGrp();
            }

            // Habilitamos los checks de las dimensiones para que puedan ser activadas.
            enabled.InventBatchIdFlag    = NoYes::Yes;
            enabled.InventSerialIdFlag   = NoYes::Yes;
            enabled.InventOwnerIdFlag_RU = NoYes::Yes;
            enabled.InventDimension1Flag = NoYes::Yes;

            if (smallGrp.visible())
            {
                show.toggleAllInventDim();
            }
            else
            {
                show.toggleAllInventDimLargeGrp();
            }

            show.ItemIdFlag    = inventDimSetupObject.setupShowItemId();
            show.ClosedQtyFlag = inventDimSetupObject.setupShowClosedQty();
            show.ClosedFlag    = inventDimSetupObject.setupShowClosed();

            if (inventDimSetupObject.setupShowAllProductDimensions())
            {
                productDim.initProductDimensionsAllGroups();
                show = InventDimParm::andParms(show, productDim);
            }

            // Habilitamos los checks de las dimensiones para que puedan ser activadas.
            show.InventBatchIdFlag    = NoYes::Yes;
            show.InventSerialIdFlag   = NoYes::Yes;
            show.InventOwnerIdFlag_RU = NoYes::Yes;
            show.InventDimension1Flag = NoYes::Yes;

            dimParmControl.formSetControls(enabled,show);
        }
    }
}
